import base64
import json


def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        token_dict = json.loads(decoded)
        if token_dict.get('valid', False):
            return token_dict.get('data', None)
    except (base64.binascii.Error, json.JSONDecodeError):
        pass
    return None

